<template><div class="page console-page"><header class="page-header"><div><div class="eyebrow">开发调试</div><h1 class="page-title">Playground</h1><p class="page-desc">使用真实 API Key 和当前账号可见的平台模型调用网关。</p></div></header><div v-if="modelError" class="inline-alert danger" role="alert">{{ modelError }}</div><div class="playground-grid"><section class="card"><div class="field"><label>网关地址</label><input class="input" :value="gatewayBase" disabled /></div><div class="field"><label for="play-key">API Key</label><input id="play-key" v-model="apiKey" class="input" type="password" autocomplete="off" placeholder="输入真实 API Key" /></div><div class="field"><label>平台模型</label><a-select v-model:value="model" :options="models" show-search option-filter-prop="label" :loading="modelsLoading" placeholder="请选择可见模型" /></div><div class="field"><label for="play-prompt">消息</label><textarea id="play-prompt" v-model="prompt" class="textarea-large" placeholder="输入消息内容"></textarea></div><button class="btn primary" :disabled="loading" @click="send">{{ loading?'请求中':'发送请求' }}</button></section><section class="card"><div class="card-title">网关响应</div><div v-if="requestError" class="inline-alert danger">{{ requestError }}</div><pre v-if="result" class="code-block">{{ result }}</pre><div v-else class="state-panel empty-state">尚未发送请求</div></section></div></div></template>
<script setup lang="ts">
import{onMounted,ref}from'vue';import axios from'axios';import{errorMessage,gatewayBase,isAdmin,list}from'../api/client';import{message}from'ant-design-vue'
const apiKey=ref(''),model=ref<string>(),prompt=ref(''),result=ref(''),loading=ref(false),modelsLoading=ref(false),modelError=ref(''),requestError=ref(''),models=ref<{label:string,value:string}[]>([])
async function loadModels(){modelsLoading.value=true;try{const path=isAdmin()?'/api/platform-models':'/api/tenant/models';models.value=(await list<any>(path)).map(row=>({label:row.displayName||row.platformModelName,value:row.platformModelName}))}catch(e){modelError.value=errorMessage(e)}finally{modelsLoading.value=false}}
async function send(){if(!apiKey.value||!model.value||!prompt.value)return message.warning('请完整填写 API Key、平台模型和消息');loading.value=true;requestError.value='';result.value='';try{const response=await axios.post(`${gatewayBase}/v1/chat/completions`,{model:model.value,messages:[{role:'user',content:prompt.value}]},{headers:{Authorization:`Bearer ${apiKey.value}`}});result.value=JSON.stringify(response.data,null,2)}catch(e){requestError.value=errorMessage(e)}finally{loading.value=false}}
onMounted(loadModels)
</script>
